hooks.onInit:
const s = world.state;
s.f1 = 0; s.f2 = 0; s.f3 = 0;
s.argA = 0; s.argB = 0; s.argC = 0;
s.forkL = 0; s.forkR = 0;

hooks.onDraw:
const s = world.state;
const A = function (v) { return Math.max(0, Math.min(1, v || 0)); };
const PJS = ' "Plus Jakarta Sans", ui-sans-serif, system-ui';
const ls = world.entities.filter(function (e) { return e.type === 'learner'; });
ls.sort(function (a, b) { return (a.y || 0) - (b.y || 0); });
for (const e of ls) world.draw.learner(e);
const argShown = Math.max(A(s.argA), A(s.argB), A(s.argC));
const cardFade = 1 - argShown;
const card = function (cx, cy, a, kind, big, small) {
  if (a < 0.01) return;
  const w = 104, h = 80;
  ctx.save();
  ctx.globalAlpha = a;
  world.draw.rrect(cx, cy, w, h, 8);
  ctx.fillStyle = '#f4efe2'; ctx.fill();
  world.draw.rrect(cx, cy, w, h, 8);
  ctx.strokeStyle = 'rgba(31,37,71,0.35)'; ctx.lineWidth = 1.4; ctx.stroke();
  const ix = cx + 14, iy = cy + 12, iw = w - 28, ih = 30;
  ctx.lineWidth = 2.2; ctx.lineJoin = 'round';
  if (kind === 'wave') {
    ctx.beginPath();
    for (let i = 0; i <= 28; i++) { const px = ix + (i / 28) * iw; const py = iy + ih / 2 - Math.sin(i / 28 * Math.PI * 4) * ih * 0.36; if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py); }
    ctx.strokeStyle = '#c0392b'; ctx.stroke();
  } else if (kind === 'eye') {
    const ex = cx + w / 2, ey = iy + ih / 2;
    ctx.beginPath(); ctx.ellipse(ex, ey, 19, 11, 0, 0, Math.PI * 2); ctx.strokeStyle = '#1F2547'; ctx.stroke();
    ctx.beginPath(); ctx.arc(ex, ey, 7, 0, Math.PI * 2); ctx.fillStyle = '#5b8def'; ctx.fill();
    ctx.beginPath(); ctx.arc(ex, ey, 3, 0, Math.PI * 2); ctx.fillStyle = '#1F2547'; ctx.fill();
  } else {
    const bx = ix, by = iy + ih * 0.72;
    ctx.beginPath();
    ctx.moveTo(bx, by); ctx.lineTo(bx + iw * 0.34, by); ctx.lineTo(bx + iw * 0.45, iy + ih * 0.08); ctx.lineTo(bx + iw * 0.55, by + ih * 0.2); ctx.lineTo(bx + iw * 0.64, by); ctx.lineTo(bx + iw, by);
    ctx.strokeStyle = '#e89a3a'; ctx.stroke();
  }
  ctx.textAlign = 'center'; ctx.textBaseline = 'alphabetic';
  ctx.fillStyle = '#1F2547'; ctx.font = '700 13px' + PJS;
  ctx.fillText(big, cx + w / 2, cy + h - 21);
  ctx.fillStyle = '#6E7896'; ctx.font = '600 9px' + PJS;
  ctx.fillText(small, cx + w / 2, cy + h - 9);
  ctx.restore();
};
card(96, 104, A(s.f1) * cardFade, 'wave', '700 nm', 'longitud de onda');
card(222, 104, A(s.f2) * cardFade, 'eye', 'conos', 'retina');
card(348, 104, A(s.f3) * cardFade, 'spike', 'señal', 'cerebro');
if (argShown > 0.01) {
  ctx.save();
  ctx.globalAlpha = Math.min(1, argShown * 1.5);
  world.draw.rrect(150, 58, 520, 256, 14);
  ctx.fillStyle = 'rgba(12,16,32,0.82)'; ctx.fill();
  world.draw.rrect(150, 58, 520, 256, 14);
  ctx.strokeStyle = 'rgba(110,120,150,0.30)'; ctx.lineWidth = 1; ctx.stroke();
  ctx.restore();
  const nodes = {};
  const NF = '600 12px' + PJS;
  if (A(s.argA) > 0.01) { ctx.save(); ctx.globalAlpha = A(s.argA); nodes.a = world.draw.node(178, 84, 232, 46, { label: 'Conoce todos los hechos físicos', fill: '#F6F2E8', labelColor: '#1F2547', font: NF }); ctx.restore(); }
  if (A(s.argB) > 0.01) { ctx.save(); ctx.globalAlpha = A(s.argB); nodes.b = world.draw.node(178, 148, 232, 46, { label: 'Al ver el rojo, aprende algo', fill: '#F6F2E8', labelColor: '#1F2547', font: NF }); ctx.restore(); }
  if (A(s.argC) > 0.01) {
    ctx.save(); ctx.globalAlpha = A(s.argC);
    nodes.c = world.draw.node(456, 110, 188, 58, { label: 'Algo escapa a lo físico', fill: '#1F2547', labelColor: '#FBFAF6', stroke: '#F4AC1D', font: '700 12px' + PJS });
    if (nodes.a) world.draw.connector(nodes.a.right, nodes.c.left, { color: '#F4AC1D', curve: 14 });
    if (nodes.b) world.draw.connector(nodes.b.right, nodes.c.left, { color: '#F4AC1D', curve: -14 });
    ctx.restore();
  }
  if (A(s.forkL) > 0.01 && nodes.c) {
    ctx.save(); ctx.globalAlpha = A(s.forkL);
    const nl = world.draw.node(170, 238, 224, 52, { label: 'Un hecho nuevo · Jackson', fill: '#a8443a', labelColor: '#FBFAF6', font: '600 11px' + PJS });
    world.draw.connector(nodes.c.bottom, nl.top, { color: '#9aa3bd', curve: 16 });
    ctx.restore();
  }
  if (A(s.forkR) > 0.01 && nodes.c) {
    ctx.save(); ctx.globalAlpha = A(s.forkR);
    const nr = world.draw.node(420, 238, 244, 52, { label: 'Solo una habilidad · Lewis, Dennett', fill: '#3f6f4f', labelColor: '#FBFAF6', font: '600 11px' + PJS });
    world.draw.connector(nodes.c.bottom, nr.top, { color: '#9aa3bd', curve: -16 });
    ctx.restore();
  }
}
